#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt;
}e[20010];
long long head[20010],tot=1;
long long n,m,s,t,d[20010],now[20010];
void add1(long long u,long long v,long long w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    for(long long i=0;i<=t;i++)
    {
        d[i]=0;
    }
    d[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,2e9);
    }
    return ans;
}
int main()
{
    scanf("%lld%lld",&m,&n);
    s=m+n+1;
    t=s+1;
    long long sum=0;
    for(long long i=1;i<=m;i++)
    {
        long long x;
        scanf("%lld",&x);
        sum+=x;
        add(s,i,x);
        char tools[10000];
        memset(tools,0,sizeof tools);
        cin.getline(tools,10000);
        int ulen=0,tool;
        while (sscanf(tools+ulen,"%d",&tool)==1)//之前已经用scanf读完了赞助商同意支付该实验的费用
        {
            add(i,tool+m,2e9);      
            if (tool==0) 
                ulen++;
            else {
                while (tool) {
                    tool/=10;
                    ulen++;
                }
            }
            ulen++;
        }
    }
    for(long long i=1;i<=n;i++)
    {
        long long x;
        scanf("%lld",&x);
        add(i+m,t,x);
    }
    long long ans=dinic();
    for(long long i=1;i<=m;i++)
    {
        if(d[i])
        {
            printf("%lld ",i);
        }
    }
    printf("\n");
    for(long long i=m+1;i<=m+n;i++)
    {
        if(d[i])
        {
            printf("%lld ",i-m);
        }
    }
    printf("\n");
    printf("%lld",sum-ans);
    return 0;
}
